import React from "react";
import { Link } from "react-router-dom";

function Admin() {
  return (
    <div className="min-h-screen bg-gradient-to-br from-green-700 via-emerald-600 to-teal-700 flex items-center justify-center p-6">
      <div className="bg-white w-full max-w-4xl rounded-3xl shadow-2xl p-8">
        
        {/* Header */}
        <div className="text-center mb-10">
          <div className="text-7xl mb-3">🚛</div>
          <h1 className="text-4xl font-bold text-gray-800">
            Admin Dashboard
          </h1>
          <p className="text-gray-500 mt-2">
            Garbage Pickup Vehicle Management System
          </p>
        </div>

        {/* Stats Cards */}
        <div className="grid md:grid-cols-3 gap-6 mb-10">
          <div className="bg-green-100 p-6 rounded-2xl shadow">
           
          </div>

          

         
        </div>

        {/* Action Buttons */}
        <div className="flex flex-col md:flex-row gap-4 justify-center">
          <Link to="/send-otp">
            <button className="bg-green-600 hover:bg-green-700 text-white px-8 py-3 rounded-xl font-semibold shadow-lg transition duration-300">
              ➕ Create User
            </button>
          </Link>

         
        </div>

      </div>
    </div>
  );
}

export default Admin;
